#include<bits/stdc++.h>
using namespace std;
string s,s1;
int a,a1,ans=0;
bool check2(int x)
{
    if(x%4!=0) return false;
    if(x%400==0) return true;
    if(x%100==0) return false;
    return true;
}
bool check(int x,string t)
{
    int t1=t[0]*10+t[1],t2=t[2]*10+t[3];
    if(t1>12||t1==0) return false;
    if(t1==1||t1==3||t1==5||t1==7||t1==8||t1==10||t1==12)
    {
        if(t2<32)return true;
        return false;
    }
    if(t1==2)
    {
        if(t2<29) return true;
        if(t2==29&&check2(x)) return true;
        return false;
    }
    if(t2<31) return true;
    return false;
}
int main()
{
    cin>>s>>s1;
    for(int i=0;i<8;i++) s[i]-='0',s1[i]-='0';
    a=s[0]*1000+s[1]*100+s[2]*10+s[3],a1=s1[0]*1000+s1[1]*100+s1[2]*10+s1[3];
    for(int i=0;i<8;i++) s[i]+='0',s1[i]+='0';
    for(int i=a;i<=a1;i++)
    {
        string t=to_string(i);
        reverse(t.begin(),t.end());
        for(int j=0;j<4;j++) t[j]-='0';
        if(!check(i,t)) continue;
        for(int j=0;j<4;j++) t[j]+='0';
        bool flag=true;
        if(i==a)
        {
            if(s.substr(4,4)>t) flag=false;
        }
        if(i==a1)
        {
            if(s1.substr(4,4)<t) flag=false;
        }
        if(flag) ans++;
    }
    cout<<ans;
    return 0;
}
